    def initialize_board(self):
        # Initialize the board with pieces
        for row in range(3, 5):
            for col in range(row % 2, 8, 2):
                self.board[row][col] = Piece('black')
                if (row + col) % 2 == 0:
                    self.board[7 - row][7 - col] = Piece('white')

    def print_board(self):
        # Print the board with pieces and alternating squares
        for row in range(8):
            for col in range(8):
                if (row + col) % 2 == 0:
                    print('.', end=' ')
                else:
                    piece = self.board[row][col]
                    if piece:
                        color = 'W' if piece.color == 'white' else 'B'
                        king = 'K' if piece.is_king else ''
                        print(f'{color}{king}', end=' ')
                    else:
                        print('.', end=' ')
            print()

    def is_valid_move(self, from_pos, to_pos):
        # Check if the move is valid
        start_row, start_col = map(int, from_pos.split())
        end_row, end_col = map(int, to_pos.split())
        piece = self.board[start_row][start_col]
        if piece and piece.color == 'white':
            if (end_row - start_row == 1 or (piece.is_king and end_row - start_row == -1)) and abs(end_col - start_col) == 1:
                return True
        return False

    def make_move(self, from_pos, to_pos):
        # Make the move if it's valid
        if self.is_valid_move(from_pos, to_pos):
            start_row, start_col = map(int, from_pos.split())
            end_row, end_col = map(int, to_pos.split())
            piece = self.board[start_row][start_col]
            self.board[end_row][end_col] = piece
            self.board[start_row][start_col] = None
            return True
        return False

    def check_win_draw(self):
        # Check for win or draw conditions
        white_count, black_count = 0, 0
        for row in range(8):
            for col in range(8):
                piece = self.board[row][col]
                if piece:
                    if piece.color == 'white':
                        white_count += 1
                    else:
                        black_count += 1
        if white_count == 0 or black_count == 0:
            print('Game Over! White wins' if black_count == 0 else 'Game Over! Black wins')
            return True
        elif (white_count + black_count) == 32 and not self.is_valid_move(str(white_count), str(black_count)):
